} from './extractHistory';

export {
  onboardingCashback,
  onboardingVoucherAbastecimento,
  onboardingVoucherEstacionamento,
} from './onboarding';

import {
  Alert,
  BackDropBottom,
  Box,
  Button,
  CardActivity,
  DetailTransactionValue,
  SeparatorHorizontal,
  TagLabel,
  Text,
} from '@semparar/design-system-app';
import type { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import theme from '@semparar/design-system-app/src/styles/theme';
import React, { FC } from 'react';
import { ActivityIndicator, Linking } from 'react-native';
import { eventSelectContent } from '~/constants/functions';
import ApiError from '../../atomic/organisms/ApiError';
import BasicScreen from '../../atomic/templates/BasicScreen';
import type { MyOrdersDetailProps } from './Models';
import { STATUS_COLORS } from './Models';
import { getAdditionalFields } from './utils';

const MyOrdersDetailView: FC<MyOrdersDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  modalizeRefInfo,
  handleOpenReportProblem,
  handleCloseReportProblem,
  handleOpenInfo,
  handleCloseInfo,
  isLoading,
  hasError,
  handleRetry,
  isCashback,
  cardTitle,
  formattedPointsValue,
  highlightText,
  formattedCurrencyValue,
  marketplaceContent,
  showOrderNumber,
  showStatus,
  showValue,
  height,
}) => {
  if (hasError) {
    return (
      <BasicScreen
        title="Detalhes do pedido"
        leftIconOnPress={handleGoBack}
        errorButtonOnPress={handleRetry || (() => {})}
      >
        <ApiError
          title="Algo deu errado!"
          subTitle="Por favor, tente de novo."
          isLoading={isLoading}
          onPress={handleRetry || (() => {})}
        />
      </BasicScreen>
    );
  }

  if (isLoading && !transaction) {
    return (
      <BasicScreen
        title="Detalhes do pedido"
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <Box flex={1} justify="center" align="center" minHeight={400}>
          <ActivityIndicator size="large" color={theme.colors.BRAND_BASE_01} />
        </Box>
      </BasicScreen>
    );
  }

  if (!transaction) {
    return null;
  }

  const additionalFields = getAdditionalFields(transaction);

  const renderDivider = () => (
    <SeparatorHorizontal
      borderWidth="smaller"
      borderColor="BRAND_COMPLEMENT_02"
      height={1}
      width="100%"
      mt="xxxxs"
    />
  );

  const renderMarketplaceContent = () => {
    if (!marketplaceContent) return null;

    return (
      <>
        <Text
          type="paragraphXL"
          color="BRAND_COMPLEMENT_01"
          mb="xxxxs"
          mt="xxxxs"
        >
          Número do pedido
        </Text>
        <Text type="paragraphMD" color="INTENSE_COLOR_03">
          #{marketplaceContent.orderNumber}
        </Text>
        {marketplaceContent.status && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Status do pedido
            </Text>
            <TagLabel
              type={(marketplaceContent.statusColor as never) || 'neutral'}
              text={marketplaceContent.status}
              showSpacing
            />
          </>
        )}
        {marketplaceContent.paymentType && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Forma de pagamento
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {marketplaceContent.paymentType}
            </Text>
          </>
        )}
        {marketplaceContent.shippingValuePoints !== undefined &&
          marketplaceContent.shippingValuePoints !== null && (
            <>
              {renderDivider()}
              <Text
                type="paragraphXL"
                color="BRAND_COMPLEMENT_01"
                mb="xxxxs"
                mt="xxxxs"
              >
                Frete
              </Text>
              <Text type="paragraphMD" color="INTENSE_COLOR_03">
                {marketplaceContent.shippingValuePoints}
              </Text>
            </>
          )}
        {marketplaceContent.valuePoints !== undefined &&
          marketplaceContent.valuePoints !== null && (
            <>
              {renderDivider()}
              <Text
                type="paragraphXL"
                color="BRAND_COMPLEMENT_01"
                mb="xxxxs"
                mt="xxxxs"
              >
                Valor total
              </Text>
              <Text type="paragraphMD" color="INTENSE_COLOR_03">
                {marketplaceContent.valuePoints}
              </Text>
            </>
          )}
        {marketplaceContent.vendorName && (
          <>
            {renderDivider()}
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Parceiro: {marketplaceContent.vendorName}
            </Text>
          </>
        )}
        {marketplaceContent.items.map((item, itemIndex: number) => (
          <CardActivity
            key={itemIndex}
            mt="nano"
            title={item.name}
            titleTextType="paragraphMD"
            description={`Quantidade: ${item.quantity}\nValor: ${item.valuePoints}`}
            descriptionTextType="paragraphSM"
            showImage={!!item.cleanedImageUrl}
            image={
              item.cleanedImageUrl ? { uri: item.cleanedImageUrl } : undefined
            }
            showIcon={false}
            iconRight={null as never}
            hideBorder={false}
          />
        ))}

        <Alert
          title="Detalhes da entrega"
          mt="meddium"
          label="Você pode acompanhar a entrega do seu pedido pelo site do parceiro."
          numberOfLines={2}
          type="highlight"
          icon="icon-truck"
          hasIconBackground
          bgIconColor="BRAND_COMPLEMENT_03"
        />
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title="Detalhes do pedido"
        isLoading={isLoading}
        leftIconOnPress={handleGoBack}
        rightIcon={
          isCashback && !transaction?.marketplace ? 'icon-help' : undefined
        }
        rightIconOnPress={handleOpenInfo}
        hasRightIcon={isCashback && !transaction?.marketplace}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? 'PLUS_COLOR_02'
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
            mb="xs"
          />

          <Box flex={1} width="100%">
            {showOrderNumber && (
              <>
                <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
                  Número do pedido
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  #{transaction.id}
                </Text>
              </>
            )}

            {showStatus && transaction.status && (
              <>
                {renderDivider()}
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  Status do pedido
                </Text>
                <TagLabel
                  type={STATUS_COLORS[transaction.status] || 'neutral'}
                  text={transaction.status}
                  showSpacing
                />
              </>
            )}

            {showValue && (
              <>
                {renderDivider()}
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  Valor
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {formattedCurrencyValue}
                </Text>
              </>
            )}

            {!marketplaceContent && additionalFields.map((field, index) => (
              <React.Fragment key={`${field.label}-${index}`}>
                {renderDivider()}
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  {field.label}
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {field.value}
                </Text>
              </React.Fragment>
            ))}

            {marketplaceContent && renderMarketplaceContent()}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="ghostLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>
      </BasicScreen>

      <BackDropBottom modalizeRef={modalizeRef as PropsModalizeRef}>
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text
              type="paragraphXXXL"
              color="BRAND_COMPLEMENT_01"
              mb="xs"
              align="center"
            >
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt="xxxxs">
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das
            9h às 17h.
          </Text>
        </Box>

        <Box align="center" width="100%" mt="xxxxs">
          <Text
            type="linkMD"
            color="INTENSE_COLOR_05"
            onPress={handleCloseReportProblem}
            align="center"
          >
            Fechar
          </Text>
        </Box>
      </BackDropBottom>

      {isCashback && (
        <BackDropBottom
          modalHeight={height * 0.3}
          modalizeRef={modalizeRefInfo as PropsModalizeRef}
        >
          <Text
            type="paragraphMD"
            align="center"
            color="INTENSE_COLOR_05"
            mt="small"
            mb="smaller"
          >
            Você também pode conferir o valor do desconto nos lançamentos da sua
            fatura.
          </Text>

          <Button text="Entendi" onPress={handleCloseInfo} />
        </BackDropBottom>
      )}
    </>
  );
};

export default MyOrdersDetailView;

import {
  BackDropBottom,
  Box,
  Button,
  CardActivity,
  DetailTransactionValue,
  SeparatorHorizontal,
  TagLabel,
  Text,
} from '@semparar/design-system-app';
import { PropsModalizeRef } from '@semparar/design-system-app/src/@types/modelize';
import React, { FC } from 'react';
import { Linking } from 'react-native';
import { eventSelectContent } from '~/constants/functions';
import BasicScreen from '../../atomic/templates/BasicScreen';
import { moment } from '../../services/moment';
import { formatToCurrency } from '../../utils/functions';
import { PointsDetailProps } from './Models';
import {
  getAdditionalFields,
  getDetailScreenTitle,
  getFormattedHighlightText,
  getFormattedPointsValue,
  getOrigin,
  getPurchaseTypeLabel,
  getTagSubType,
  getTransactionGainType,
  getVehicleInfo,
} from './utils';

const PointsDetailView: FC<PointsDetailProps> = ({
  handleGoBack,
  transaction,
  modalizeRef,
  handleOpenReportProblem,
  handleCloseReportProblem,
}) => {
  const gainType = getTransactionGainType(transaction);
  const tagSubType = getTagSubType(transaction);
  const screenTitle = getDetailScreenTitle(gainType, transaction.type);
  const vehicleInfo = getVehicleInfo(transaction);
  const purchaseTypeLabel = getPurchaseTypeLabel(tagSubType);
  const origin = getOrigin(transaction);
  const additionalFields = getAdditionalFields(transaction);
  const formattedCurrencyValue = formatToCurrency(transaction.currencyValue);
  const formattedPointsValue = getFormattedPointsValue(
    transaction.amount,
    transaction.type,
  );
  const cardTitle = transaction.description || '';
  const highlightText = getFormattedHighlightText(
    transaction.date,
    gainType,
    moment,
  );

  const renderDivider = () => {
    return (
      <SeparatorHorizontal
        borderWidth="smaller"
        borderColor="BRAND_COMPLEMENT_02"
        height={1}
        width="100%"
        mt="xxxxs"
      />
    );
  };

  const renderTagContent = () => {
    const hasVehicleInfo = !!vehicleInfo && vehicleInfo !== '';
    const shouldShowOrigin = origin && !hasVehicleInfo;
    const hasPurchaseTypeLabel =
      !!purchaseTypeLabel && purchaseTypeLabel !== '';

    return (
      <>
        {renderDivider()}
        {shouldShowOrigin && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Origem
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {origin}
            </Text>
            {renderDivider()}
          </>
        )}
        {hasVehicleInfo && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tag
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {vehicleInfo}
            </Text>
            {renderDivider()}
          </>
        )}

        {hasPurchaseTypeLabel && (
          <>
            <Text
              type="paragraphXL"
              color="BRAND_COMPLEMENT_01"
              mb="xxxxs"
              mt="xxxxs"
            >
              Tipo de compra
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {purchaseTypeLabel}
            </Text>
          </>
        )}
      </>
    );
  };

  return (
    <>
      <BasicScreen
        title={screenTitle}
        leftIconOnPress={handleGoBack}
        hasScroll
        errorButtonOnPress={() => {}}
      >
        <DetailTransactionValue
          icon={transaction.icon as never}
          title={cardTitle}
          titleColor="BRAND_COMPLEMENT_01"
          iconBgColor="BRAND_COMPLEMENT_03"
          points={formattedPointsValue}
          bgColor="BRAND_COMPLEMENT_02"
          pointsColor={
            transaction.type === 'CREDIT' || transaction.type === 'REFUNDED'
              ? 'PLUS_COLOR_02'
              : ('INTENSE_COLOR_05' as const)
          }
        />

        <Box ml="smaller" mr="smaller" mt="xxxxs" flex={1}>
          <TagLabel
            icon={undefined}
            type="neutral"
            text={highlightText}
            showSpacing
          />

          <Box mt="xxxs" flex={1} width="100%">
            <Text type="paragraphXL" color="BRAND_COMPLEMENT_01" mb="xxxxs">
              Valor
            </Text>
            <Text type="paragraphMD" color="INTENSE_COLOR_03">
              {formattedCurrencyValue}
            </Text>

            {gainType === 'TAG' && renderTagContent()}

            {additionalFields.map((field, index) => (
              <React.Fragment key={`${field.label}-${index}`}>
                {renderDivider()}
                <Text
                  type="paragraphXL"
                  color="BRAND_COMPLEMENT_01"
                  mb="xxxxs"
                  mt="xxxxs"
                >
                  {field.label}
                </Text>
                <Text type="paragraphMD" color="INTENSE_COLOR_03">
                  {field.value}
                </Text>
              </React.Fragment>
            ))}
          </Box>

          <Box width="100%" align="flex-end" mb="small">
            <Button
              type="secundaryLarge"
              text="Relatar Problema"
              onPress={handleOpenReportProblem}
            />
          </Box>
        </Box>
      </BasicScreen>

      <BackDropBottom modalizeRef={modalizeRef as PropsModalizeRef}>
        <Box align="center" width="100%" mt="xxs">
          <Box align="center" width="100%">
            <Text
              type="paragraphXXXL"
              color="BRAND_COMPLEMENT_01"
              mb="xs"
              align="center"
            >
              Central de Atendimento
            </Text>
          </Box>
        </Box>

        <Box pd="innerSmall">
          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Capitais"
            description="4002 1552"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_capitais',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });
              Linking.openURL('tel:40021552');
            }}
          />

          <CardActivity
            mt="nano"
            icon="icon-contact"
            title="Demais localidades"
            description="0800 015 0252"
            iconRight="icon-next"
            showIcon
            showTagLabel={false}
            onPress={() => {
              eventSelectContent({
                content_type: 'cta',
                content_id: 'telefones_demais_localidades',
                location_1: 'monetizacao',
                location_2: 'hub_recompensas_spmais',
                location_3: 'contato_telefones',
              });

              Linking.openURL('tel:08000150252');
            }}
          />
          <Text type="paragraphXS" color="INTENSE_COLOR_04" mt="xxxxs">
            *Atendimento de segunda à sexta das 9h às 21h. Sábado e domingo das
            9h às 17h.
          </Text>
        </Box>

        <Box align="center" width="100%" mt="xxxxs">
          <Text
            type="linkMDM"
            color="INTENSE_COLOR_05"
            onPress={handleCloseReportProblem}
            align="center"
          >
            Fechar
          </Text>
        </Box>
      </BackDropBottom>
    </>
  );
};

export default PointsDetailView;

import React, { useState } from 'react';
import { ScrollView, View, Pressable } from 'react-native';
import {
  Text,
  Box,
  CardPoints,
  Header,
  Icon,
  SearchUsed,
  SeparatorHorizontal,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  extractHistoryLoaded,
  extractHistoryEmpty,
} from '../services/sdui/mocks';

registerAllAdapters();

type ViewState = 'loaded' | 'empty';

const SCREENS: Record<ViewState, SDUIScreen> = {
  loaded: extractHistoryLoaded,
  empty: extractHistoryEmpty,
};

function ViewToggle({
  selected,
  onSelect,
}: {
  selected: ViewState;
  onSelect: (v: ViewState) => void;
}) {
  const labels: Record<ViewState, string> = {
    loaded: 'Loaded (8)',
    empty: 'Empty',
  };

  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16 }}>
      {(['loaded', 'empty'] as const).map(v => (
        <Pressable
          key={v}
          onPress={() => onSelect(v)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {labels[v]}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

function ExtractDemo() {
  const [view, setView] = useState<ViewState>('loaded');
  const screen = useSDUIJsonEditor(SCREENS[view]);

  return (
    <ScrollView style={{ flex: 1 }}>
      <View style={{ padding: 24, maxWidth: 420 }}>
        <Text type="headingMDL" mb="nano">
          SDUI: Extrato
        </Text>
        <Text type="bodyMD" mb="smaller" color="INTENSE_COLOR_03">
          Renders the transaction history from JSON via SDUI engine. Transactions
          use context interpolation — edit the JSON to change data dynamically.
          Tab switching is visual-only — content filtering requires backend
          support via separate context data per tab.
        </Text>

        <ViewToggle selected={view} onSelect={setView} />

        <Box pd="squishSmall" bgColor="LIGHT_BASE_02" br="sm">
          <ScreenRenderer screen={screen} />
        </Box>
      </View>
    </ScrollView>
  );
}

const REAL_TRANSACTIONS = (extractHistoryLoaded.context.transactions as Record<string, string>[]).map(t => ({
  icon: String(t.icon),
  title: String(t.title),
