import React from 'react';
import { DetailTransactionValue } from '@semparar/design-system-app';
import type { SDUIComponentProps, SDUIContext } from '../models';

interface DetailHeaderProps extends SDUIComponentProps {
  icon: string;
  title: string;
  points: string;
  pointsColor?: string;
  titleColor?: string;
  iconBgColor?: string;
  bgColor?: string;
}

const POINTS_COLOR_MAP: Record<string, string> = {
  green: 'PLUS_COLOR_02',
  red: 'INTENSE_COLOR_05',
};

export default function DetailHeaderAdapter({
  props,
}: {
  props: DetailHeaderProps;
  context: SDUIContext;
}) {
  const {
    icon,
    title,
    points,
    pointsColor = 'green',
    titleColor = 'BRAND_COMPLEMENT_01',
    iconBgColor = 'BRAND_COMPLEMENT_03',
    bgColor = 'BRAND_COMPLEMENT_02',
  } = props;

  const resolvedPointsColor = POINTS_COLOR_MAP[pointsColor] ?? pointsColor;

  return (
    <DetailTransactionValue
      icon={icon as never}
      title={String(title)}
      titleColor={titleColor}
      iconBgColor={iconBgColor}
      points={String(points)}
      bgColor={bgColor}
      pointsColor={resolvedPointsColor as never}
    />
  );
}

