import React, { useState } from 'react';
import { ScrollView, View, Pressable } from 'react-native';
import {
  Text,
  Box,
  Button,
  DetailTransactionValue,
  Header,
  SeparatorHorizontal,
  TagLabel,
  Alert,
  CardActivity,
} from '@semparar/design-system-app';
import type { Meta, StoryObj } from 'storybook/internal/types';
import type { SDUIScreen } from '../services/sdui/models';
import ScreenRenderer from '../services/sdui/renderer/ScreenRenderer';
import { registerAllAdapters } from '../services/sdui/adapters';
import { useSDUIJsonEditor } from '../../.storybook/addons/json-editor';
import {
  orderDetailVoucher,
  orderDetailCashback,
  orderDetailMarketplace,
  orderDetailTag,
} from '../services/sdui/mocks';

registerAllAdapters();

type Variant = 'voucher' | 'cashback' | 'marketplace' | 'tag';

const SCREENS: Record<Variant, SDUIScreen> = {
  voucher: orderDetailVoucher,
  cashback: orderDetailCashback,
  marketplace: orderDetailMarketplace,
  tag: orderDetailTag,
};

const LABELS: Record<Variant, string> = {
  voucher: 'Voucher',
  cashback: 'Cashback',
  marketplace: 'Marketplace',
  tag: 'TAG',
};

function VariantToggle({
  selected,
  onSelect,
}: {
  selected: Variant;
  onSelect: (v: Variant) => void;
}) {
  return (
    <View style={{ flexDirection: 'row', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
      {(['voucher', 'cashback', 'marketplace', 'tag'] as const).map(v => (
        <Pressable
          key={v}
          onPress={() => onSelect(v)}
          style={{
            paddingHorizontal: 16,
            paddingVertical: 8,
            borderRadius: 20,
            backgroundColor: selected === v ? '#6B2FBE' : '#E8E0F0',
          }}
        >
          <Text
            type="paragraphMDM"
            color={selected === v ? 'LIGHT_BASE_01' : 'INTENSE_COLOR_05'}
          >
            {LABELS[v]}
          </Text>
        </Pressable>
      ))}
    </View>
  );
}

function OrderDetailDemo() {
  const [variant, setVariant] = useState<Variant>('voucher');
  const screen = useSDUIJsonEditor(SCREENS[variant]);

