  const resolvedPointsColor = POINTS_COLOR_MAP[pointsColor] ?? pointsColor;

  return (
    <DetailTransactionValue
      icon={icon as never}
      title={String(title)}
      titleColor={titleColor}
      iconBgColor={iconBgColor}
      points={String(points)}
      bgColor={bgColor}
      pointsColor={resolvedPointsColor as never}
    />
  );
}

